import{_ as t,o as n,c as e,a2 as o}from"./chunks/framework.CHeM0PsO.js";const k=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"pengantar/login-navigasi.md","filePath":"pengantar/login-navigasi.md","lastUpdated":1784467494000}'),r={name:"pengantar/login-navigasi.md"};function i(s,a,l,u,g,d){return n(),e("div",null,[...a[0]||(a[0]=[o('<h2 id="bab-2-cara-masuk-login-navigasi" tabindex="-1">BAB 2: CARA MASUK (LOGIN) &amp; NAVIGASI <a class="header-anchor" href="#bab-2-cara-masuk-login-navigasi" aria-label="Permalink to &quot;BAB 2: CARA MASUK (LOGIN) &amp; NAVIGASI&quot;">​</a></h2><h3 id="_2-1-membuka-aplikasi" tabindex="-1">2.1 Membuka Aplikasi <a class="header-anchor" href="#_2-1-membuka-aplikasi" aria-label="Permalink to &quot;2.1 Membuka Aplikasi&quot;">​</a></h3><p>Aplikasi Zero Cafe dibuka melalui browser HP atau laptop menggunakan link (URL) khusus yang diberikan oleh Acronimous Studio. Tidak perlu mengunduh atau memasang aplikasi dari Play Store/App Store.</p><h3 id="_2-2-layar-login-satu-kolom-pintar" tabindex="-1">2.2 Layar Login (Satu Kolom Pintar) <a class="header-anchor" href="#_2-2-layar-login-satu-kolom-pintar" aria-label="Permalink to &quot;2.2 Layar Login (Satu Kolom Pintar)&quot;">​</a></h3><p>Saat halaman terbuka, Anda hanya akan melihat <strong>satu kotak input di tengah layar</strong>. Tidak ada tombol &quot;SPV&quot; atau &quot;GM&quot; — cukup masukkan kode akses Anda:</p><table tabindex="0"><thead><tr><th>Kode yang Dimasukkan</th><th>Hasilnya</th></tr></thead><tbody><tr><td><strong><code>Zero123</code></strong></td><td>Masuk sebagai <strong>GM/Owner</strong> → langsung diarahkan ke Dashboard GM</td></tr><tr><td><strong><code>1234</code></strong></td><td>Masuk sebagai <strong>SPV Outlet Perintis</strong> → diarahkan ke Menu Utama SPV</td></tr><tr><td><strong><code>5678</code></strong></td><td>Masuk sebagai <strong>SPV Outlet Dg Tata</strong> → diarahkan ke Menu Utama SPV</td></tr></tbody></table><blockquote><p><strong>Catatan Keamanan:</strong> PIN SPV menentukan outlet mana yang terkunci. Setelah login, SPV <strong>tidak bisa mengubah outlet</strong>. Ini mencegah kesalahan atau manipulasi data antar cabang.</p></blockquote><h3 id="_2-3-menu-utama-spv" tabindex="-1">2.3 Menu Utama SPV <a class="header-anchor" href="#_2-3-menu-utama-spv" aria-label="Permalink to &quot;2.3 Menu Utama SPV&quot;">​</a></h3><p>Setelah login berhasil, SPV akan melihat 4 tombol utama:</p><ol><li><strong>Laporan Harian</strong> — Mengisi laporan operasional 9 Tab (atau melanjutkan Fase 2 jika ada yang tertunda)</li><li><strong>Laporan Mingguan</strong> — Evaluasi taktis 7 hari</li><li><strong>Laporan Bulanan</strong> — Evaluasi strategis 1 bulan penuh</li><li><strong>Pengaturan Parameter</strong> — Mengatur target omset, mendaftarkan event, dan mengelola data staf</li></ol><hr>',11)])])}const h=t(r,[["render",i]]);export{k as __pageData,h as default};
